import { ethers } from "ethers";

const RPC_URL = process.env.ETH_RPC_URL || "https://mainnet.infura.io/v3/YOUR_INFURA_KEY";
const PRIVATE_KEY = process.env.ETH_PRIVATE_KEY || "YOUR_PRIVATE_KEY";

if (!RPC_URL || !PRIVATE_KEY || PRIVATE_KEY === "YOUR_PRIVATE_KEY") {
  throw new Error("Missing or invalid ETH_RPC_URL / ETH_PRIVATE_KEY configuration");
}

const provider = new ethers.JsonRpcProvider(RPC_URL);
const wallet = new ethers.Wallet(PRIVATE_KEY, provider);

export function getProvider() {
  return provider;
}

export function getWallet() {
  return wallet;
}

export async function getAddress() {
  return await wallet.getAddress();
}

export async function getEthBalance(address) {
  const balance = await provider.getBalance(address);
  return ethers.formatEther(balance);
}

export async function sendETH({ to, amountEth, gasLimit, maxFeePerGasGwei, maxPriorityFeePerGasGwei, nonce }) {
  if (!ethers.isAddress(to)) {
    throw new Error("Invalid recipient address");
  }

  const tx = {
    to,
    value: ethers.parseEther(String(amountEth)),
  };

  if (gasLimit) tx.gasLimit = BigInt(gasLimit);
  if (nonce !== undefined) tx.nonce = nonce;

  if (maxFeePerGasGwei || maxPriorityFeePerGasGwei) {
    tx.maxFeePerGas = maxFeePerGasGwei ? ethers.parseUnits(String(maxFeePerGasGwei), "gwei") : undefined;
    tx.maxPriorityFeePerGas = maxPriorityFeePerGasGwei
      ? ethers.parseUnits(String(maxPriorityFeePerGasGwei), "gwei")
      : undefined;
  }

  const response = await wallet.sendTransaction(tx);
  const receipt = await response.wait();

  return {
    hash: response.hash,
    blockNumber: receipt?.blockNumber ?? null,
    status: receipt?.status ?? null,
    from: response.from,
    to: response.to,
    value: response.value.toString(),
  };
}

export function getContract(contractAddress, abi, signerOrProvider = wallet) {
  if (!ethers.isAddress(contractAddress)) {
    throw new Error("Invalid contract address");
  }
  return new ethers.Contract(contractAddress, abi, signerOrProvider);
}

export async function callContractRead({ contractAddress, abi, method, args = [] }) {
  const contract = getContract(contractAddress, abi, provider);

  if (typeof contract[method] !== "function") {
    throw new Error(`Method ${method} does not exist on contract`);
  }

  const result = await contract[method](...args);
  return result;
}

export async function sendContractTransaction({
  contractAddress,
  abi,
  method,
  args = [],
  valueEth,
  gasLimit,
  maxFeePerGasGwei,
  maxPriorityFeePerGasGwei,
  nonce,
}) {
  const contract = getContract(contractAddress, abi, wallet);

  if (typeof contract[method] !== "function") {
    throw new Error(`Method ${method} does not exist on contract`);
  }

  const overrides = {};

  if (valueEth !== undefined) {
    overrides.value = ethers.parseEther(String(valueEth));
  }
  if (gasLimit) {
    overrides.gasLimit = BigInt(gasLimit);
  }
  if (nonce !== undefined) {
    overrides.nonce = nonce;
  }
  if (maxFeePerGasGwei) {
    overrides.maxFeePerGas = ethers.parseUnits(String(maxFeePerGasGwei), "gwei");
  }
  if (maxPriorityFeePerGasGwei) {
    overrides.maxPriorityFeePerGas = ethers.parseUnits(String(maxPriorityFeePerGasGwei), "gwei");
  }

  const txResponse = await contract[method](...args, overrides);
  const receipt = await txResponse.wait();

  return {
    hash: txResponse.hash,
    blockNumber: receipt?.blockNumber ?? null,
    status: receipt?.status ?? null,
    from: txResponse.from,
    to: txResponse.to,
  };
}

export async function estimateEthTransferGas({ to, amountEth }) {
  if (!ethers.isAddress(to)) {
    throw new Error("Invalid recipient address");
  }

  const gas = await provider.estimateGas({
    from: await wallet.getAddress(),
    to,
    value: ethers.parseEther(String(amountEth)),
  });

  return gas.toString();
}

export async function estimateContractGas({
  contractAddress,
  abi,
  method,
  args = [],
  valueEth,
}) {
  const contract = getContract(contractAddress, abi, wallet);

  if (!contract[method]?.estimateGas) {
    throw new Error(`Method ${method} does not support gas estimation`);
  }

  const overrides = {};
  if (valueEth !== undefined) {
    overrides.value = ethers.parseEther(String(valueEth));
  }

  const gas = await contract[method].estimateGas(...args, overrides);
  return gas.toString();
}

export async function getTransaction(txHash) {
  return await provider.getTransaction(txHash);
}

export async function getTransactionReceipt(txHash) {
  return await provider.getTransactionReceipt(txHash);
}

